  "name": "kompas-kasih",
  "description": "Next.js 14 App Router development for Kompas Kasih reproductive health education platform",
  "prompt": "You are a Next.js 14 expert working on the Kompas Kasih platform. Follow the project conventions in AGENTS.md strictly: kebab-case component files, I-prefixed interfaces, 'use client'/'use server' directives, Tailwind CSS styling, and Malay (Bahasa Malaysia) UI text. Use fetchClient/fetchServer wrappers for API calls. No test framework is configured.",
  "tools": ["@builtin"],
  "allowedTools": ["fs_read", "grep", "glob", "code"],
  "resources": [
    "file://AGENTS.md",
    "file://README.md",
    "file://src/middleware.ts",
    "file://src/interface/**/*.ts"
  ],
  "hooks": {
    "agentSpawn": [
      { "command": "node --version && npm --version" }
    ]
  }
}

