.PHONY: help setup up down clean build exec npm

SHELL := /bin/bash

ENV_FILE := .env
DOCKER_DIR := docker/development

help:
	@echo "=========================================="
	@echo "  Next.js Client Docker Makefile"
	@echo "=========================================="
	@echo "Usage: make <command> [cmd=<command>]"
	@echo ""
	@echo "Commands:"
	@echo "  setup    - Initial setup (copies .env and installs deps)"
	@echo "  up       - Start containers"
	@echo "  down     - Stop containers"
	@echo "  clean    - Stop and wipe containers, networks, and volumes"
	@echo "  build    - Force rebuild the Docker image"
	@echo "  exec     - SSH into the container (sh)"
	@echo "  npm      - Run npm commands (e.g., make npm cmd='install axios')"

setup:
	@echo "Setting up Next.js environment..."
	@if [ ! -f $(ENV_FILE) ]; then cp .env.example $(ENV_FILE); echo "Created .env file"; fi
	@make build
	@make up
	@echo "Installing dependencies..."
	@make npm cmd="install"

up:
	@echo "Starting Next.js environment..."
	@cd $(DOCKER_DIR) && docker compose --env-file ../../$(ENV_FILE) up -d
	@echo ""
	@echo "App running at: http://localhost:3000"

down:
	@echo "Stopping Next.js environment..."
	@cd $(DOCKER_DIR) && docker compose down

clean:
	@echo "Cleaning Next.js environment..."
	@cd $(DOCKER_DIR) && docker compose down -v --rmi local

build:
	@echo "Building Next.js image..."
	@cd $(DOCKER_DIR) && docker compose build --no-cache

exec:
	@echo "Entering container shell..."
	@cd $(DOCKER_DIR) && docker compose exec client sh

npm:
	@echo "Executing npm $(cmd) in client container..."
	@cd $(DOCKER_DIR) && docker compose exec client npm $(cmd)

