"use client";

import { signIn } from "next-auth/react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import CycleArrowIcon from "./icons/cycle-arrow-icon";
import { apiFetch } from "@/lib/api";

type SuccessResponse = {
  email: string;
  name: string;
  email_verified_at: string;
  access_token: string;
};

const VerifyOTPForm = ({ email }: { email: string }) => {
  const router = useRouter();

  const [otp, setOtp] = useState<string[]>(["", "", "", "", "", ""]);
  const [isResendDisabled, setIsResendDisabled] = useState<boolean>(false);
  const [timer, setTimer] = useState<number>(600);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [isVerified, setIsVerified] = useState<boolean>(false);
  const [successResponse, setSuccessResponse] = useState<SuccessResponse>();

  const handleOtpChange = (index: number, value: string) => {
    if (value.match(/^[0-9]$/)) {
      const updatedOtp = [...otp];
      updatedOtp[index] = value;
      setOtp(updatedOtp);

      if (index < otp.length - 1) {
        const nextInput = document.getElementById(`otp-input-${index + 1}`) as HTMLInputElement;
        nextInput?.focus();
      }
    }
  };

  const handleOtpBackspace = (index: number) => {
    const updatedOtp = [...otp];
    updatedOtp[index] = "";
    setOtp(updatedOtp);

    if (index > 0) {
      const prevInput = document.getElementById(`otp-input-${index - 1}`) as HTMLInputElement;
      prevInput?.focus();
    }
  };

  const handleOtpPaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
    const pastedText = e.clipboardData.getData("Text");

    if (/^\d{6}$/.test(pastedText)) {
      const updatedOtp = pastedText.split("");
      setOtp(updatedOtp);

      const lastInput = document.getElementById(`otp-input-5`) as HTMLInputElement;
      lastInput?.focus();
    }
  };

  const forceLogin = async () => {
    if (successResponse) {
      setIsSubmitting(true);

      try {
        const loginResult = await signIn("otp-login", {
          redirect: false,
          email: successResponse.email,
          name: successResponse.name,
          email_verified_at: successResponse.email_verified_at,
          access_token: successResponse.access_token,
        });

        if (loginResult?.error) {
          setError("Login failed. Please try again.");
          throw new Error(loginResult.error);
        }

        router.push("/");
      } catch (error) {
        setError("Something went wrong. Please try again.");
      }
    }
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    const otpCode = otp.join("");

    if (otpCode.length !== 6) {
      setError("Please enter a valid 6-digit OTP.");
      return;
    }

    if (typeof email !== "string") {
      setError("Invalid email.");
      return;
    }

    try {
      const response = await apiFetch("/api/verify-otp", {
        method: "POST",
        headers: {
          Accept: "application/json",
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email, otp: otpCode }),
      });

      const data = await response.json();

      if (!response.ok) {
        return setError(data.message);
      }

      setIsVerified(true);
      setSuccessResponse({
        access_token: data.access_token,
        email: data.user.email,
        email_verified_at: data.user.email_verified_at,
        name: data.user.name,
      });
    } catch (error) {
      console.error(error);
    } finally {
      setIsSubmitting(false);
    }
  };

