        onSubmit={handleSubmit}
        className="w-full md:w-6/12 lg:w-4/12 xl:w-3/12 flex flex-col gap-[1.625rem]"
      >
        <h1 className="text-[#4F4F4F] text-xl font-semibold text-center">PENGESAHAN EMEL</h1>
        <div className="flex flex-col gap-5">
          <p className="text-lg font-medium leading-[22px]">
            Sila masukkan kod keselamatan 6 digit anda yang kami hantar ke{" "}
            {email.replace(/(.{2})(.*)(?=@)/, (match, first, middle) => {
              return first + "*".repeat(middle.length);
