          </p>

          <div className="flex items-center gap-[0.625rem]">
            <p className="text-lg font-medium leading-[22px]">Did not received it? </p>
            <button
              className="px-[0.625rem] py-[0.4375rem] flex items-center gap-[0.375rem] bg-[#F1F1F2] rounded-md"
              type="button"
              onClick={handleResendOtp}
              disabled={isResendDisabled || isSubmitting}
            >
              <CycleArrowIcon className="text-black" />
              Resend {isResendDisabled && `(${Math.floor(timer / 60)}:${timer % 60})`}
            </button>
          </div>

          <div className="flex items-center gap-[0.625rem] justify-center">
            <div className="flex gap-1">
              {otp.map((digit, index) => (
                <input
                  key={index}
                  id={`otp-input-${index}`}
                  type="number"
                  inputMode="numeric"
                  maxLength={1}
                  value={digit}
                  onChange={(e) => handleOtpChange(index, e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Backspace") {
                      handleOtpBackspace(index);
                    }
                  }}
                  onPaste={handleOtpPaste}
                  className="w-[2.375rem] h-[2.375rem] aspect-square text-[#545454] text-lg font-normal border-2 border-[#E1E3EA] rounded-[0.25rem] text-center"
                  autoFocus={index === 0}
                />
              ))}
            </div>
            <button
              type="submit"
              className="btn-primary w-fit"
            >
              Verify
            </button>
          </div>

          {isVerified && (
            <p className="text-lg font-medium leading-[22px] text-[#0094FF] text-center">
              Kod anda berjaya disahkan.
            </p>
          )}

          {error && <p className="input-text-error text-center">{error}</p>}
        </div>

        <button
          onClick={forceLogin}
          type="button"
          className="btn-primary"
          disabled={!isVerified}
        >
          {isSubmitting ? "Mengesahkan..." : "Sahkan Sekarang"}
        </button>

        <Link
          href="/register"
          className="btn-secondary-plain"
        >
          Kembali ke Daftar
        </Link>
      </form>
    </div>
  );
};

export default VerifyOTPForm;

