            {email.replace(/(.{2})(.*)(?=@)/, (match, first, middle) => {
              return first + "*".repeat(middle.length);
            })}
          </p>

          <div className="flex items-center gap-[0.625rem]">
            <p className="text-lg font-medium leading-[22px]">Did not received it? </p>
            <button
              className="px-[0.625rem] py-[0.4375rem] flex items-center gap-[0.375rem] bg-[#F1F1F2] rounded-md"
              type="button"
              onClick={handleResendOtp}
              disabled={isResendDisabled || isSubmitting}
            >
              <CycleArrowIcon className="text-black" />
